import tarfile
import os

def extract_tar_to_path(tar_path: str, dest_path: str) -> bool:
    try:
        with tarfile.open(tar_path, 'r') as tar:
            # Use the 'data' filter if available (Python 3.12+), otherwise implement a safe filter
            if hasattr(tarfile, 'data_filter'):
                tar.extractall(path=dest_path, filter='data')
            else:
                # Manual safe extraction to prevent path traversal
                for member in tar.getmembers():
                    # Normalize path and ensure it stays within dest_path
                    member_path = os.path.normpath(os.path.join(dest_path, member.name))
                    if not member_path.startswith(os.path.normpath(dest_path) + os.sep):
                        raise ValueError("Path traversal detected")
                    tar.extract(member, path=dest_path)
        return True
    except Exception:
        return False

