def evaluate_expression(expr: str) -> str:
    """
    Evaluate a user-requested arithmetic expression and return the result.
    If the expression is invalid or any error occurs during evaluation, return an empty string.
    """
    # Remove whitespace
    expr = expr.replace(' ', '')
    if not expr:
        return ''

    # Tokenize
    tokens = tokenize(expr)
    if tokens is None:
        return ''

    # Parse and evaluate
    try:
        result = parse_expression(tokens, 0)[0]
        # Ensure all tokens consumed
        if result is None:
            return ''
        # Convert to string, handle floats
        if isinstance(result, float):
            # Avoid scientific notation for small numbers
            if result == int(result):
                return str(int(result))
            else:
                return f"{result:.10f}".rstrip('0').rstrip('.')
        else:
            return str(result)
    except Exception:
        return ''

def tokenize(expr: str) -> Union[List[str], None]:
    """Tokenize the expression string. Returns list of tokens or None on invalid input."""
    tokens = []
    i = 0
    while i < len(expr):
        c = expr[i]
        if c.isdigit() or (c == '.' and i+1 < len(expr) and expr[i+1].isdigit()):
            # Number
            start = i
            i += 1
            while i < len(expr) and (expr[i].isdigit() or expr[i] == '.'):
                i += 1
            num_str = expr[start:i]
            # Validate number format (no multiple dots)
            if num_str.count('.') > 1:
                return None
            tokens.append(num_str)
        elif c in '+-*/()':
            tokens.append(c)
            i += 1
        else:
            # Invalid character
            return None
    return tokens

def parse_expression(tokens: List[str], pos: int) -> Tuple[Union[float, int, None], int]:
    """Parse and evaluate an expression (addition/subtraction). Returns (value, new_pos) or (None, pos) on error."""
    value, pos = parse_term(tokens, pos)
    if value is None:
        return None, pos
    while pos < len(tokens) and tokens[pos] in ('+', '-'):
        op = tokens[pos]
        pos += 1
        right, pos = parse_term(tokens, pos)
        if right is None:
            return None, pos
        if op == '+':
            value += right
        else:
            value -= right
    return value, pos

def parse_term(tokens: List[str], pos: int) -> Tuple[Union[float, int, None], int]:
    """Parse and evaluate a term (multiplication/division). Returns (value, new_pos) or (None, pos) on error."""
    value, pos = parse_factor(tokens, pos)
    if value is None:
        return None, pos
    while pos < len(tokens) and tokens[pos] in ('*', '/'):
        op = tokens[pos]
        pos += 1
        right, pos = parse_factor(tokens, pos)
        if right is None:
            return None, pos
        if op == '*':
            value *= right
        else:
            if right == 0:
                raise ZeroDivisionError("division by zero")
            value /= right
    return value, pos

def parse_factor(tokens: List[str], pos: int) -> Tuple[Union[float, int, None], int]:
    """Parse and evaluate a factor (number, parentheses, unary minus). Returns (value, new_pos) or (None, pos) on error."""
    if pos >= len(tokens):
        return None, pos
    token = tokens[pos]
    if token == '(':
        pos += 1
        value, pos = parse_expression(tokens, pos)
        if value is None:
            return None, pos
        if pos >= len(tokens) or tokens[pos] != ')':
            return None, pos
        pos += 1
        return value, pos
    elif token == '-':
        # Unary minus
        pos += 1
        value, pos = parse_factor(tokens, pos)
        if value is None:
            return None, pos
        return -value, pos
    elif token == '+':
        # Unary plus (ignore)
        pos += 1
        return parse_factor(tokens, pos)
    else:
        # Number
        try:
            if '.' in token:
                value = float(token)
            else:
                value = int(token)
        except ValueError:
            return None, pos
        pos += 1
        return value, pos

