import json

def makePickleData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it before returning it
    '''
    # Use JSON instead of pickle to avoid deserialization vulnerabilities (CWE-502)
    # Convert payload to a dictionary if it's an object
    if hasattr(payload, '__dict__'):
        data = payload.__dict__
    elif isinstance(payload, dict):
        data = payload
    else:
        # Fallback: try to serialize directly (may raise TypeError)
        data = payload
    return json.dumps(data).encode('utf-8')

